struct MapCardView: UIViewRepresentable {
    func makeUIView(context: Context) -> GMSMapView {
        let camera = GMSCameraPosition(latitude: 37.7749, longitude: -122.4194, zoom: 12.5)
        let mapView = GMSMapView(frame: .zero, camera: camera)
        mapView.isMyLocationEnabled = false
        mapView.settings.compassButton = true
        mapView.settings.myLocationButton = false

        let marker = GMSMarker(position: CLLocationCoordinate2D(latitude: 37.7765, longitude: -122.4167))
        marker.title = "Pickup"
        marker.snippet = "Market St"
        marker.map = mapView

        let marker2 = GMSMarker(position: CLLocationCoordinate2D(latitude: 37.7686, longitude: -122.4294))
        marker2.title = "Dropoff"
        marker2.snippet = "Mission District"
        marker2.map = mapView

        let path = GMSMutablePath()
        path.add(marker.position)
        path.add(marker2.position)
        let line = GMSPolyline(path: path)
        line.strokeColor = UIColor.systemBlue
        line.strokeWidth = 5
        line.map = mapView

        return mapView
    }

    func updateUIView(_ uiView: GMSMapView, context: Context) {}
}

final class CheckoutViewModel: ObservableObject {
    enum Event {
        case showMessage(String, String)
    }

    private let eventSubject = SimpleSubject<Event>()
