    @Published private(set) var isReady: Bool = true
    @Published private(set) var buttonTitle: String = "Pay with Stripe (Demo)"

    private var paymentSheet: PaymentSheet?

    func reset() {
        paymentSheet = nil
        isReady = true
        buttonTitle = "Pay with Stripe (Demo)"
        eventSubject.send(.showMessage("Reset", "Demo state reset."))
    }

    func preparePaymentSheetIfNeeded() {
        guard paymentSheet == nil else { return }

        let customerConfig = PaymentSheet.CustomerConfiguration(id: "demo_customer", ephemeralKeySecret: "ek_test_demo_ephemeral_key_secret")
        var config = PaymentSheet.Configuration()
        config.merchantDisplayName = "Demo Company"
        config.allowsDelayedPaymentMethods = false
        config.customer = customerConfig
        config.returnURL = "demoapp://stripe-redirect"
        config.applePay = .init(merchantId: "merchant.com.demo.pitch", merchantCountryCode: "US")

        let clientSecret = "pi_test_demo_client_secret"
        paymentSheet = PaymentSheet(paymentIntentClientSecret: clientSecret, configuration: config)

        eventSubject.send(.showMessage("Demo Mode", "PaymentSheet prepared with placeholder secrets. Replace with real PaymentIntent client secret + Ephemeral Key from your backend when ready."))
    }

    func presentPaymentSheet() {
        guard let paymentSheet else {
            eventSubject.send(.showMessage("Not Ready", "PaymentSheet not prepared."))
            return
        }
        guard let topVC = UIApplication.shared.topMostViewController() else {
            eventSubject.send(.showMessage("Error", "Unable to find a view controller to present PaymentSheet."))
            return
        }

        paymentSheet.present(from: topVC) { [weak self] result in
            guard let self else { return }
            switch result {
            case .completed:
                self.eventSubject.send(.showMessage("Payment", "Completed (if configured with real backend secrets)."))
            case .canceled:
                self.eventSubject.send(.showMessage("Payment", "Canceled."))
            case .failed(let error):
                self.eventSubject.send(.showMessage("Payment Failed", error.localizedDescription))
            }
        }
    }
}

final class SimpleSubject<T> {
    private var observers: [(T) -> Void] = []
    var publisher: SimplePublisher<T> { SimplePublisher(subject: self) }
    func send(_ value: T) { observers.forEach { $0(value) } }
    fileprivate func observe(_ handler: @escaping (T) -> Void) { observers.append(handler) }
}

struct SimplePublisher<T> {
    fileprivate let subject: SimpleSubject<T>
    func sink(_ handler: @escaping (T) -> Void) { subject.observe(handler) }
}

extension View {
    func onReceive<T>(_ publisher: SimplePublisher<T>, perform action: @escaping (T) -> Void) -> some View {
        self.onAppear { publisher.sink(action) }
    }
}

extension UIApplication {
    func topMostViewController(base: UIViewController? = nil) -> UIViewController? {
        let baseVC: UIViewController? = {
            if let base { return base }
            if let scene = connectedScenes.compactMap({ $0 as? UIWindowScene }).first,
               let root = scene.windows.first(where: { $0.isKeyWindow })?.rootViewController {
                return root
            }
            return nil
        }()

        if let nav = baseVC as? UINavigationController {
            return topMostViewController(base: nav.visibleViewController)
        }
        if let tab = baseVC as? UITabBarController, let selected = tab.selectedViewController {
            return topMostViewController(base: selected)
        }
        if let presented = baseVC?.presentedViewController {
            return topMostViewController(base: presented)
        }
        return baseVC
    }
}